-- RealityDB Logistics Template | Seed: 42 | ~160 rows
-- Lifecycle: cancelled purchase_orders → delivered_at = NULL
-- Temporal: delivered_at > created_at
-- Weights: country China=30% USA=25% Germany=15% India=15% Brazil=10% Other=5% | po_status delivered=50% shipped=20% pending=15% cancelled=15%

CREATE TABLE suppliers (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name TEXT NOT NULL, country TEXT NOT NULL, contact_email TEXT, rating NUMERIC(2,1) NOT NULL, tier TEXT NOT NULL, created_at TIMESTAMP NOT NULL);
CREATE TABLE purchase_orders (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), supplier_id UUID NOT NULL REFERENCES suppliers(id), status TEXT NOT NULL, total NUMERIC(12,2) NOT NULL, priority TEXT NOT NULL, shipped_at TIMESTAMP, delivered_at TIMESTAMP, created_at TIMESTAMP NOT NULL);
CREATE TABLE shipment_tracking (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), purchase_order_id UUID NOT NULL REFERENCES purchase_orders(id), carrier TEXT NOT NULL, status TEXT NOT NULL, location TEXT, updated_at TIMESTAMP NOT NULL, created_at TIMESTAMP NOT NULL);
CREATE TABLE inventory (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), supplier_id UUID NOT NULL REFERENCES suppliers(id), product_name TEXT NOT NULL, sku TEXT NOT NULL, quantity INTEGER NOT NULL, warehouse TEXT NOT NULL, reorder_point INTEGER NOT NULL, created_at TIMESTAMP NOT NULL);




